CREATE OR REPLACE VIEW vm_kep_t_monthly_receive_det (membership_no, receive_seq, keeping_type_code, receive_month, receive_description, period, principal_of_loan, interest, money_amount, principal_balance_of_loan, receive_year, seq_no, share_stock, clearloan_status, newitem_status, money_amount_not, interest_not, principal_not, posting_status, unkeep_money_amount) AS SELECT sc_kep_t_monthly_receive_det.membership_no,
         sc_kep_t_monthly_receive_det.receive_seq,
         sc_kep_t_monthly_receive_det.keeping_type_code,
         sc_kep_t_monthly_receive_det.receive_month,
         sc_kep_t_monthly_receive_det.receive_description,
         sc_kep_t_monthly_receive_det.period,
         sc_kep_t_monthly_receive_det.principal_of_loan,
         sc_kep_t_monthly_receive_det.interest,
         sc_kep_t_monthly_receive_det.money_amount,

        CASE
            WHEN sc_kep_m_ucf_keeping_item_type.keeping_type_group = 'LON' THEN
                mpost_principal_balance + unkeep_principal_of_loan
            WHEN sc_kep_m_ucf_keeping_item_type.keeping_type_group = 'ISP' THEN
                mpost_principal_balance + unkeep_principal_of_loan
            WHEN sc_kep_m_ucf_keeping_item_type.keeping_type_group = 'COL' THEN
                principal_balance_of_loan
            ELSE
                mpost_principal_balance - unkeep_money_amount
        END AS principal_balance_of_loan,
                
         
         sc_kep_t_monthly_receive_det.receive_year,
         sc_kep_t_monthly_receive_det.seq_no,
         sc_kep_t_monthly_receive_det.share_stock,
         sc_kep_t_monthly_receive_det.clearloan_status,
         sc_kep_t_monthly_receive_det.newitem_status,
         CASE WHEN sc_kep_m_ucf_keeping_item_type.keeping_type_code='MR00' THEN  money_amount  ELSE money_amount_not END  AS money_amount_not, --MR00 used money_amount
         sc_kep_t_monthly_receive_det.interest_not,
         sc_kep_t_monthly_receive_det.principal_not,
--         sc_kep_t_monthly_receive_det.principal_of_loan_edit,
--         sc_kep_t_monthly_receive_det.interest_edit,
--         sc_kep_t_monthly_receive_det.money_amount_edit,
--         sc_kep_t_monthly_receive_det.period_edit,
         sc_kep_t_monthly_receive_det.posting_status ,
         sc_kep_t_monthly_receive_det.unkeep_money_amount  
    FROM sc_kep_t_monthly_receive_det,
         sc_kep_t_monthly_receive
        ,sc_kep_m_ucf_keeping_item_type 
        ,sc_acc_m_account_year
        ,sc_mem_m_membership_registered         
   WHERE ( sc_kep_t_monthly_receive_det.membership_no = sc_kep_t_monthly_receive.membership_no ) and ( sc_kep_t_monthly_receive_det.receive_year = sc_kep_t_monthly_receive.receive_year ) and ( sc_kep_t_monthly_receive.receive_month = sc_kep_t_monthly_receive_det.receive_month ) and ( sc_kep_t_monthly_receive_det.seq_no = sc_kep_t_monthly_receive.seq_no )
AND sc_kep_t_monthly_receive_det.keeping_type_code = sc_kep_m_ucf_keeping_item_type.keeping_type_code         
and sc_kep_t_monthly_receive.receipt_date >= sc_acc_m_account_year.beginning_of_account
AND sc_acc_m_account_year.account_year = 2020
